```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract TokenVoting {
    address private _owner;
    bytes32[] private _candidateNames;
    mapping(uint256 => uint256) private _candidateVotes;
    mapping(address => bool) private _voters;
    bool private _inVote;

    event CandidateAdded(uint256 indexed candidateId, bytes32 name);
    event VotingRightsGranted(address voter);
    event VoteCast(address voter, uint256 candidateId);

    constructor() {
        _owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == _owner, "Not owner");
        _;
    }

    modifier preventReentrancy() {
        require(!_inVote, "Reentrancy detected");
        _inVote = true;
        _;
        _inVote = false;
    }

    function candidateCount() public view returns (uint256) {
        return _candidateNames.length;
    }

    function candidateNames(uint256 index) public view returns (bytes32) {
        require(index < _candidateNames.length, "Invalid candidate index");
        return _candidateNames[index];
    }

    function candidateVotes(uint256 index) public view returns (uint256) {
        require(index < _candidateNames.length, "Invalid candidate index");
        return _candidateVotes[index];
    }

    function addCandidate(string memory name) public onlyOwner {
        bytes32 candidateName = keccak256(abi.encodePacked(name));
        _candidateNames.push(candidateName);
        emit CandidateAdded(_candidateNames.length - 1, candidateName);
    }

    function grantVotingRights(address voter) public onlyOwner {
        require(!_voters[voter], "Voting rights already granted");
        _voters[voter] = true;
        emit VotingRightsGranted(voter);
    }

    function hasVotingRights(address voter) public view returns (bool) {
        return _voters[voter];
    }

    function vote(uint256 candidateId) public preventReentrancy {
        require(hasVotingRights(msg.sender), "No voting rights");
        require(candidateId < _candidateNames.length, "Invalid candidate ID");
        require(_candidateVotes[candidateId] == 0, "Already voted");

        _candidateVotes[candidateId]++;
        _voters[msg.sender] = false; // revoke voting rights after casting a vote
        emit VoteCast(msg.sender, candidateId);
    }
}
